def reciprocal_rank_fusion(ranked_lists, k=60):
    """ranked_lists: a list of lists of doc ids, each already in rank order."""
    scores = {}
    for ranked in ranked_lists:
        for rank, doc_id in enumerate(ranked, start=1):   # rank is 1-based
            scores[doc_id] = scores.get(doc_id, 0.0) + 1.0 / (k + rank)
    # sort doc ids by fused score, highest first
    return sorted(scores, key=scores.get, reverse=True)

# Two retrievers, two ranked lists of doc ids:
keyword_hits = ["D1", "D2", "D7", "D9"]   # from BM25
vector_hits  = ["D2", "D5", "D1", "D4"]   # from embedding search

fused = reciprocal_rank_fusion([keyword_hits, vector_hits])
print(fused)   # -> ['D2', 'D1', 'D5', ...]  D2 floats to the top
